class Solution:
    def rankTeams(self, votes):
        m = len(votes[0])
        teams = list(votes[0])
        counts = {t: [0] * m for t in teams}
        for v in votes:
            for i, t in enumerate(v):
                counts[t][i] += 1
        teams.sort(key=lambda t: ([-counts[t][i] for i in range(m)], t))
        return ''.join(teams)

