var rankTeams = function(votes) {
    const m = votes[0].length;
    const teams = [...votes[0]];
    const counts = {};
    for (const t of teams) counts[t] = new Array(m).fill(0);
    for (const v of votes)
        for (let i = 0; i < m; i++) counts[v[i]][i]++;
    teams.sort((a, b) => {
        for (let i = 0; i < m; i++) {
            if (counts[b][i] !== counts[a][i]) return counts[b][i] - counts[a][i];
        }
        return a < b ? -1 : 1;
    });
    return teams.join('');
};
